=SELECT value 
FROM "SensorData" sd
JOIN "SensorType" st ON sd.sensorID = st.sensorID
WHERE sd.userID = {{ $('Webhook heart rate').item.json.body.UserID }}
AND sd.watchID = {{ $('Webhook heart rate').item.json.body.SmartWatchID }}
AND sd.phoneID = {{ $('Webhook heart rate').item.json.body.AndroidID }}
AND st.name = 'HeartRate'
ORDER BY time DESC
LIMIT 10;

